INSERT INTO chat_message 
(
   room_id
 , user_id
 , message
) 
VALUES 
(
   #{roomId}
 , #{userId}
 , #{message}
)

INSERT INTO chat_room_user 
(
   room_id
 , user_id
 , entered_at
) 
VALUES 
(
   #{roomId}
 , #{userId}
 , NOW()
)

INSERT INTO chat_room 
(
      title
    , created_at
) 
VALUES 
(
      #{title}
    , NOW()
)
